mapper.delete:
DELETE FROM 
    user_role
WHERE 
    member_id = #{memberId}
AND 
    role_id = #{roleId}

mapper.update:
UPDATE 
    user_role
SET 
    chg_id = CASE



                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN #{userRole.chgId}


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN chg_id



        ELSE chg_id
    END,
    chg_dt = CASE



                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN COALESCE(#{userRole.chgDt}, NOW())


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN chg_dt



        ELSE chg_dt
    END,
    del_id = 



                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN NULL::uuid


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN #{userRole.delId}


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN del_id


        ,
    del_dt = 



                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN NULL::timestamp


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN #{userRole.delDt}


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN del_dt


        ,
    del_yn = CASE



                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN #{userRole.delYn}


                    WHEN user_id = #{userRole.userId}
                    AND role_id = #{userRole.roleId}
                    THEN del_yn



        ELSE del_yn
    END
WHERE 
    (user_id, role_id) IN 

        (#{userRole.userId}, #{userRole.roleId})

mapper.select:
SELECT ur.user_id, ur.role_id, u.user_name, r.role_name, ur.reg_id, ur.reg_dt, ur.chg_id, ur.chg_dt, ur.del_id, ur.del_dt, ur.del_yn FROM user_role ur INNER JOIN user u ON ur.user_id = u.user_id INNER JOIN role r ON ur.role_id = r.role_id
AND ur.user_id IN
#{userId}
AND ur.role_id IN
#{roleId}
AND u.user_name ILIKE '%' || #{filter.userName} || '%'
AND r.role_name ILIKE '%' || #{filter.roleName} || '%'
AND ur.del_yn = #{filter.delYn}
AND u.del_yn = #{filter.parentIsActive} AND r.del_yn = #{filter.parentIsActive}
